package com.example.yourapp;

import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.view.View;
import android.widget.ImageView;
import android.widget.TextView;

import androidx.appcompat.app.AppCompatActivity;

import java.util.ArrayList;

public class ShareReceiverActivity extends AppCompatActivity {

    private TextView textView;
    private ImageView imageView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_share_receiver);

        textView = findViewById(R.id.textView);
        imageView = findViewById(R.id.imageView);

        Intent intent = getIntent();
        String action = intent.getAction();
        String type = intent.getType();

        if (Intent.ACTION_SEND.equals(action) && type != null) {
            handleSendIntent(intent);
        } else if (Intent.ACTION_SEND_MULTIPLE.equals(action) && type != null) {
            handleSendMultipleIntent(intent);
        } else {
            // No specific content shared or unsupported action
            textView.setText("No specific content shared or unsupported action.");
            imageView.setVisibility(View.GONE);
            textView.setVisibility(View.VISIBLE);
        }
    }

    private void handleSendIntent(Intent intent) {
        String type = intent.getType();
        if ("text/plain".equals(type)) {
            String sharedText = intent.getStringExtra(Intent.EXTRA_TEXT);
            if (sharedText != null) {
                textView.setText("Shared Text:\n" + sharedText);
                imageView.setVisibility(View.GONE);
                textView.setVisibility(View.VISIBLE);
            } else {
                textView.setText("No text content found.");
                imageView.setVisibility(View.GONE);
                textView.setVisibility(View.VISIBLE);
            }
        } else if (type != null && type.startsWith("image/")) {
            Uri imageUri = intent.getParcelableExtra(Intent.EXTRA_STREAM);
            if (imageUri != null) {
                imageView.setImageURI(imageUri);
                // Grant temporary read permission to the URI.
                // This is often handled by the system for ACTION_SEND, but good practice.
                grantUriPermission(getPackageName(), imageUri, Intent.FLAG_GRANT_READ_URI_PERMISSION);
                imageView.setVisibility(View.VISIBLE);
                textView.setVisibility(View.GONE);
            } else {
                textView.setText("No image content found.");
                imageView.setVisibility(View.GONE);
                textView.setVisibility(View.VISIBLE);
            }
        } else {
            textView.setText("Unsupported single content type: " + type);
            imageView.setVisibility(View.GONE);
            textView.setVisibility(View.VISIBLE);
        }
    }

    private void handleSendMultipleIntent(Intent intent) {
        String type = intent.getType();
        if (type != null && type.startsWith("image/")) {
            ArrayList<Uri> imageUris = intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM);
            if (imageUris != null && !imageUris.isEmpty()) {
                // For simplicity, we'll display the first image.
                // In a real application, you might use a RecyclerView or a custom view to display multiple images.
                Uri firstImageUri = imageUris.get(0);
                imageView.setImageURI(firstImageUri);
                // Grant temporary read permission to the URI.
                grantUriPermission(getPackageName(), firstImageUri, Intent.FLAG_GRANT_READ_URI_PERMISSION);

                textView.setText("Received " + imageUris.size() + " images. Displaying the first one.");
                imageView.setVisibility(View.VISIBLE);
                textView.setVisibility(View.VISIBLE); // Keep text visible to show count
            } else {
                textView.setText("No multiple images found.");
                imageView.setVisibility(View.GONE);
                textView.setVisibility(View.VISIBLE);
            }
        } else {
            textView.setText("Unsupported multiple content type: " + type);
            imageView.setVisibility(View.GONE);
            textView.setVisibility(View.VISIBLE);
        }
    }
}